AreaEventManager = class("AreaEventManager", EventObservable)

function AreaEventManager:init()
    self.eventTime = -1

    self:registerEvent(S2CNoticeAreaEvent, function(data)
        self:onNoticeAreaEvent(data)
    end)

    self:registerEvent(S2CNoticeNextAreaEvent, function(data)
        self:onNoticeNextAreaEvent(data)
    end)

    self:registerEvent(S2CNoticeReward, function(data)
        self:onNoticeReward(data)
    end)

    self:registerEvent(S2CWrestlingNotification, function(data)
        local builder = DataBuilder.new():fromData(data)
        local winnerName = builder:getParam("winnerName") or ""
        local data = {
            top = true,
            message = string.format(Lang:getString("wrestling.notification"), winnerName),
        }
        HostApi.showNotification(json.encode(data))
        --print("S2CWrestlingNotification " .. data.message)
    end)

    LuaTimer:cancel(self.tickKey)
    self.tickKey = LuaTimer:schedule(function()
        self:onTick()
    end, 0, 1000)
end

function AreaEventManager:onNoticeAreaEvent(data)
    local builder = DataBuilder.new():fromData(data)
    self.eventId = builder:getNumberParam("eventId")
    self.noticeMessage = builder:getParam("noticeMessage")
    self.eventTime = builder:getNumberParam("eventTime") --事件时间
    self.needMuscle = builder:getNumberParam("needMuscle")
    self.rewardType = builder:getNumberParam("rewardType")
    self.rewardNum = builder:getNumberParam("rewardNum")
    self.AreaTeleportPos = StringUtil.split(builder:getParam("strAreaTeleportPos"), ",")

    local player = PlayerManager:getClientPlayer()
    if player and player.property
            and player.property.muscleMass >= self.needMuscle
            and not player.property.isAdvancing then
        CustomDialog.builder()
            .setContentText(Lang:getString(self.noticeMessage))
            .setShowTime(GameConfig.eventDlgLiveTime, true)
            .setRightClickListener(function()
            self:onTeleportAreaEvent(self.eventId)
        end).show()
    end

    if GUIMainControlTool then
        GUIMainControlTool:startAreaEventCd(self.eventTime, self.needMuscle, self.rewardType, self.rewardNum)
    end
end

function AreaEventManager:onNoticeNextAreaEvent(data)
    local builder = DataBuilder.new():fromData(data)
    local AreaEventInterval = builder:getNumberParam("AreaEventInterval")
    if GUIMainControlTool then
        GUIMainControlTool:startNextAreaEventCd(AreaEventInterval)
    end
end

function AreaEventManager:onTeleportAreaEvent(eventId)
    local params = {
        eventId = eventId
    }
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData("TeleportAreaEvent", data)
end

function AreaEventManager:onNoticeReward(data)
    local builder = DataBuilder.new():fromData(data)
    local type = builder:getNumberParam("type")
    local num = builder:getNumberParam("num")

    CustomDialog.builder()
                .setContentText(Lang:getString("reward.text") .. Utility.toKMBString(tostring(num), 2) .. Lang:getString("reward_type_" .. type))
                .setCloseVisible(false)
                .setLeftText(nil)
                .setShowTime(GameConfig.eventDlgLiveTime)
                .setDisableTime(GameConfig.eventDlgDisableTime)
                .show()
end

function AreaEventManager:onTick()
    if self.eventTime >= 0 then
        self:showAreaInfo()
        self.eventTime = self.eventTime - 1
    end
end

function AreaEventManager:showAreaInfo()

end

return AreaEventManager